def process_saml_response(saml_response_b64):
    """
    Process and validate a SAML response.
    Returns extracted user information if valid.
    Raises SAMLValidationError if validation fails.
    """
    # Decode base64
    try:
        xml_bytes = base64.b64decode(saml_response_b64, validate=True)
    except Exception as e:
        raise SAMLValidationError(f"Invalid base64 encoding in SAML response: {e}")

    # Parse XML safely
    root = _parse_saml_xml(xml_bytes)

    # Validate root element is a SAML Response
    expected_tag = f'{{{SAML_NAMESPACES["samlp"]}}}Response'
    if root.tag != expected_tag:
        raise SAMLValidationError(
            f"Root element is not a SAML Response: {root.tag}"
        )

    # Validate InResponseTo if we have a stored request ID
    in_response_to = root.get('InResponseTo')
    if 'saml_request_id' in session:
        if in_response_to != session.get('saml_request_id'):
            raise SAMLValidationError(
                "InResponseTo does not match the original SAML request ID"
            )

    # Validate response timing
    _validate_response_timing(root)

    # Validate destination
    _validate_destination(root)

    # Validate issuer
    _validate_issuer(root)

    # Validate status
    _validate_response_status(root)

    # Find assertion(s)
    assertions = root.findall('saml:Assertion', SAML_NAMESPACES)
    if not assertions:
        raise SAMLValidationError("No Assertion found in SAML response")

    if len(assertions) > 1:
        raise SAMLValidationError(
            "Multiple assertions found; only single assertion is supported"
        )

    assertion = assertions[0]

    # Validate assertion ID for replay prevention
    assertion_id = assertion.get('ID')
    if not assertion_id:
        raise SAMLValidationError("Assertion has no ID attribute")
    _check_replay(assertion_id)

    # Validate assertion issuer
    assertion_issuer = assertion.find('saml:Issuer', SAML_NAMESPACES)
    if assertion_issuer is not None and assertion_issuer.text:
        if assertion_issuer.text.strip() != IDP_ENTITY_ID:
            raise SAMLValidationError(
                f"Assertion Issuer mismatch: {assertion_issuer.text.strip()}"
            )

    # Validate conditions (time validity and audience)
    _validate_conditions(assertion)

    # Validate subject confirmation
    _validate_subject_confirmation(assertion)

    # Extract user information
    name_id = _extract_name_id(assertion)
    if name_id is None:
        raise SAMLValidationError("No NameID found in assertion Subject")

    attributes = _extract_attributes(assertion)
    session_index = _extract_session_index(assertion)

    # Sanitize all extracted values
    sanitized_attributes = {}
    for key, value in attributes.items():
        sanitized_key = _sanitize_attribute_value(key)
        sanitized_value = _sanitize_attribute_value(value)
        sanitized_attributes[sanitized_key] = sanitized_value

    return {
        'name_id': name_id,
        'attributes': sanitized_attributes,
        'session_index': session_index,
        'assertion_id': assertion_id,
    }


def generate_csrf_token():
    """Generate a CSRF token tied to the session."""
    if 'csrf_nonce' not in session:
        session['csrf_nonce'] = secrets.token_hex(32)
    nonce = session['csrf_nonce']
    token = hmac.new(
        CSRF_SECRET.encode(), nonce.encode(), hashlib.sha256
    ).hexdigest()
    return token


def validate_csrf_token(token):
    """Validate a CSRF token against the session."""
    if 'csrf_nonce' not in session:
        return False
    nonce = session['csrf_nonce']
    expected = hmac.new(
        CSRF_SECRET.encode(), nonce.encode(), hashlib.sha256
    ).hexdigest()
    return hmac.compare_digest(token, expected)


def login_required(f):
    """Decorator to require authentication."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user' not in session:
            return redirect('/saml/login')
        # Check session expiry
        if 'session_expires' in session:
            expires = datetime.fromisoformat(session['session_expires'])
            if datetime.now(timezone.utc) >= expires:
                session.clear()
                return redirect('/saml/login')
        return f(*args, **kwargs)
    return decorated_function


def _generate_saml_request_id():
    """Generate a unique SAML request ID."""
    return f"_id-{secrets.token_hex(16)}"


@app.after_request
def set_security_headers(response):
    """Set security headers on all responses."""
    response.headers['X-Content-Type-Options'] = 'nosniff'
    response.headers['X-Frame-Options'] = 'DENY'
    response.headers['X-XSS-Protection'] = '1; mode=block'
    response.headers['Strict-Transport-Security'] = 'max-age=31536000; includeSubDomains'
    response.headers['Cache-Control'] = 'no-store, no-cache, must-revalidate'
    response.headers['Pragma'] = 'no-cache'
    response.headers['Content-Security-Policy'] = (
        "default-src 'self'; script-src 'none'; object-src 'none'; "
        "frame-ancestors 'none'"
    )
    return response


@app.route('/saml/login')
def saml_login():
    """Initiate SAML authentication by redirecting to the IdP."""
    # Generate a unique request ID
    request_id = _generate_saml_request_id()
    session['saml_request_id'] = request_id
    session['saml_relay_state'] = secrets.token_hex(16)

    # Generate SAML AuthnRequest
    issue_instant = datetime.now(timezone.utc).strftime('%Y-%m-%dT%H:%M:%SZ')
    authn_request = f'''<samlp:AuthnRequest
        xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
        xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
        ID="{request_id}"
        Version="2.0"
        IssueInstant="{issue_instant}"
        Destination="{IDP_SSO_URL}"
        AssertionConsumerServiceURL="{SP_ACS_URL}"
        ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST">
        <saml:Issuer>{SP_ENTITY_ID}</saml:Issuer>
        <samlp:NameIDPolicy
            Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress"
            AllowCreate="false"/>
    </samlp:AuthnRequest>'''

    encoded_request = base64.b64encode(authn_request.encode()).decode()

    # Return an auto-submitting form for POST binding
    html = f'''<!DOCTYPE html>
<html>
<head><title>Redirecting to Identity Provider...</title></head>
<body onload="document.forms[0].submit();">
    <noscript>
        <p>JavaScript is required. Please click the button below to continue.</p>
    </noscript>
    <form method="POST" action="{IDP_SSO_URL}">
        <input type="hidden" name="SAMLRequest" value="{encoded_request}" />
        <input type="hidden" name="RelayState" value="{session['saml_relay_state']}" />
        <noscript>
            <input type="submit" value="Continue to Identity Provider" />
        </noscript>
    </form>
</body>
</html>'''

    response = make_response(html)
    response.headers['Content-Type'] = 'text/html; charset=utf-8'
    return response


@app.route('/saml/acs', methods=['POST'])
def saml_acs():
    """
    Assertion Consumer Service endpoint.
    Receives and processes SAML responses from the IdP.
    """
    saml_response_b64 = request.form.get('SAMLResponse')
    if not saml_response_b64:
        app.logger.warning("No SAMLResponse in POST data")
        abort(400, description="Missing SAMLResponse parameter")

    # Validate RelayState if we set one
    relay_state = request.form.get('RelayState', '')
    if 'saml_relay_state' in session:
        if not hmac.compare_digest(relay_state, session.get('saml_relay_state', '')):
            app.logger.warning("RelayState mismatch - possible CSRF")
            abort(403, description="Invalid RelayState")

    try:
        user_info = process_saml_response(saml_response_b64)
    except SAMLValidationError as e:
        app.logger.error(f"SAML validation failed: {e}")
        abort(403, description="SAML authentication failed")
    except Exception as e:
        app.logger.error(f"Unexpected error processing SAML response: {e}")
        abort(500, description="Internal error processing authentication")

    # Create user session
    session.clear()  # Clear any existing session data
    session.regenerate = True  # Signal to regenerate session ID

    # Regenerate session to prevent session fixation
    session['user'] = {
        'name_id': user_info['name_id']['value'],
        'name_id_format': user_info['name_id']['format'],
        'attributes': user_info['attributes'],
    }
    session['session_index'] = user_info.get('session_index')
    session['authenticated'] = True
    session['auth_time'] = datetime.now(timezone.utc).isoformat()
    session['session_expires'] = (
        datetime.now(timezone.utc) + timedelta(hours=1)
    ).isoformat()
    session['csrf_nonce'] = secrets.token_hex(32)
    session.permanent = True

    # Extract common attributes for convenience
    attrs = user_info['attributes']
    email = attrs.get(
        'http://schemas.xmlsoap.org/ws/2005/05/identity/claims/emailaddress',
        attrs.get('email', user_info['name_id']['value'])
    )
    display_name = attrs.get(
        'http://schemas.xmlsoap.org/ws/2005/05/identity/claims/name',
        attrs.get('displayName', email)
    )
    session['user']['email'] = email
    session['user']['display_name'] = display_name

    app.logger.info(f"User authenticated via SAML: {email}")

    return redirect('/dashboard')


@app.route('/saml/logout')
@login_required
def saml_logout():
    """Log out the user and clear the session."""
    user_email = session.get('user', {}).get('email', 'unknown')
    session.clear()
    app.logger.info(f"User logged out: {user_email}")
    return redirect('/')


