def internal_error(e):
    return jsonify({'error': 'Internal Server Error'}), 500


if __name__ == '__main__':
    import logging
    logging.basicConfig(level=logging.INFO)

    # Ensure required environment variables are set in production
    if os.environ.get('FLASK_ENV') == 'production':
        required_vars = [
            'FLASK_SECRET_KEY', 'SP_ENTITY_ID', 'SP_ACS_URL',
            'IDP_SSO_URL', 'IDP_ENTITY_ID', 'CSRF_SECRET',
        ]
        missing = [v for v in required_vars if not os.environ.get(v)]
        if missing:
            raise RuntimeError(
                f"Missing required environment variables: {', '.join(missing)}"
            )

    # In production, use a proper WSGI server like gunicorn
    # gunicorn -w 4 -b 0.0.0.0:8443 --certfile cert.pem --keyfile key.pem app:app
    app.run(
        host='127.0.0.1',
        port=8443,
        debug=False,
    )